1	import { describe, it, expect } from "vitest";
2	import { createQuote, processClaim, processMultipleDamages } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office System", () => {
5	  // Quote Operations - Base Functionality
6	  describe("Quote Operations", () => {
7	    it("should return 5G for empty item list (processing fee only)", () => {
8	      expect(createQuote([])).toBe(5);
9	    });
10	
11	    it("should calculate base premium for single sword", () => {
12	      expect(createQuote([{ type: "sword", damage: 50 }])).toBe(105);
13	    });
14	    it("should calculate base premium for single amulet", () => {
15	      expect(createQuote([{ type: "amulet", damage: 50 }])).toBe(65);
16	    });
17	    it("should calculate base premium for single staff", () => {
18	      expect(createQuote([{ type: "staff", damage: 50 }])).toBe(85);
19	    });
20	    it("should calculate base premium for single potion", () => {
21	      expect(createQuote([{ type: "potion", damage: 50 }])).toBe(75);
22	    });
23	    it("should calculate base premium for single component", () => {
24	      expect(createQuote([{ type: "component", damage: 50 }])).toBe(55);
25	    });
26	
27	    it("should add processing fee to calculated premium", () => {
28	      expect(createQuote([{ type: "component", damage: 50 }, { type: "potion", damage: 50 }])).toBe(125);
29	    });
30	
31	    it("should sum premiums for two different items", () => {
32	      expect(createQuote([{ type: "sword", damage: 50 }, { type: "amulet", damage: 50 }])).toBe(175);
33	    });
34	    it.todo("should sum premiums for three different items");
35	
36	    it("should apply cursed item surcharge (50%)", () => {
37	      expect(createQuote([{ type: "sword", damage: 50, cursed: true }])).toBe(160);
38	    });
39	    it.todo("should apply enchanted item surcharge (level 5) to sword");
40	    it("should apply high enchantment surcharge (level 5+, 30%)", () => {
41	      expect(createQuote([{ type: "sword", damage: 50, enchantment: 5 }])).toBe(130);
42	    });
43	    it("should apply cursed surcharge and enchanted surcharge together", () => {
44	      expect(createQuote([{ type: "sword", damage: 50, cursed: true, enchantment: 5 }])).toBe(185);
45	    });
46	
47	    it("should apply long-standing customer discount (2+ years)", () => {
48	      expect(createQuote([{ type: "sword", damage: 50 }], { yearsAsCustomer: 2 })).toBe(84);
