1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	  dragonMaterial?: boolean;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const SWORD_BASE_PREMIUM = 100;
11	const AMULET_BASE_PREMIUM = 60;
12	const STAFF_BASE_PREMIUM = 80;
13	const POTION_BASE_PREMIUM = 70;
14	const COMPONENT_BASE_PREMIUM = 50;
15	
16	const FRACTIONAL_THRESHOLD_LOW = 0.45;
17	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
18	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
19	
20	const ITEM_PREMIUMS: Record<string, number> = {
21	  sword: SWORD_BASE_PREMIUM,
22	  amulet: AMULET_BASE_PREMIUM,
23	  staff: STAFF_BASE_PREMIUM,
24	  potion: POTION_BASE_PREMIUM,
25	  component: COMPONENT_BASE_PREMIUM,
26	};
27	
28	function getItemBasePremium(itemType: string): number | undefined {
29	  return ITEM_PREMIUMS[itemType];
30	}
31	
32	function hasCursedItem(items: QuoteItem[]): boolean {
33	  return items.some(item => item.cursed);
34	}
35	
36	function isHighEnchantment(item: QuoteItem): boolean {
37	  return item.enchantment !== undefined && item.enchantment >= 5;
38	}
39	
40	function hasHighEnchantment(items: QuoteItem[]): boolean {
41	  return items.some(isHighEnchantment);
42	}
43	
44	function shouldApplyMultiItemFee(items: QuoteItem[], maxPremium: number): boolean {
45	  return items.length > 1 && maxPremium >= 100;
46	}
47	
48	function calculateProcessingFee(items: QuoteItem[]): number {
49	  const hasEnchanted = hasHighEnchantment(items);
50	  const hasCursed = hasCursedItem(items);
51	
52	  // Enchanted items without curse: no processing fee
53	  if (hasEnchanted && !hasCursed) {
54	    return 0;
55	  }
56	
57	  // Cursed items without enchantment: increased fee
58	  if (hasCursed && !hasEnchanted) {
59	    return 10;
60	  }
61	
62	  // Check for multi-item surcharge
63	  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
64	  if (shouldApplyMultiItemFee(items, maxPremium)) {
65	    return PROCESSING_FEE + 10;
66	  }
67	
68	  return PROCESSING_FEE;
69	}
70	
71	function calculateItemPremium(item: QuoteItem): number {
72	  const basePremium = getItemBasePremium(item.type);
73	  if (basePremium === undefined) {
74	    throw new Error(`Unknown item type: ${item.type}`);
75	  }
76	  let premium = basePremium;
77	  if (item.cursed) {
78	    premium += basePremium * 0.5;
79	  }
80	  if (isHighEnchantment(item)) {
81	    premium += basePremium * 0.3;
82	  }
83	  return premium;
84	}
85	
86	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
87	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
88	    return total * 0.8;
89	  }
90	  return total;
91	}
92	
93	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
94	  if (isFirstInsurance) {
95	    return total * 1.1;
96	  }
97	  return total;
98	}
99	
100	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
101	  if (isFollowUpContract) {
102	    return Math.floor(total * 0.85);
103	  }
104	  return total;
105	}
106	
107	function applyFirstInsuranceRoundingAdjustment(total: number, isFirstInsurance?: boolean): number {
108	  const rounded = Math.ceil(total);
109	  const fractional = total % 1;
110	
111	  // Mid-range decimals (0.45-0.55) are subject to special rounding for first insurance
112	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
113	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
114	  const shouldApplyExtraRound = isFirstInsurance && hasMidRangeDecimal && isLowValue;
115	
116	  if (shouldApplyExtraRound) {
117	    return rounded + 1;
118	  }
119	
120	  return rounded;
121	}
122	
123	interface QuoteOptions {
124	  yearsAsCustomer?: number;
125	  yearsWithMHPCO?: number;
126	  isFirstInsurance?: boolean;
127	  isFollowUpContract?: boolean;
128	}
129	
130	function applyQuoteModifiers(total: number, options?: QuoteOptions): number {
131	  // Apply modifiers in sequence: discount -> surcharge -> discount -> rounding
132	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
133	  let modifiedTotal = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
134	  modifiedTotal = applyFirstInsuranceSurcharge(modifiedTotal, options?.isFirstInsurance);
135	  modifiedTotal = applyFollowUpContractDiscount(modifiedTotal, options?.isFollowUpContract);
136	  return applyFirstInsuranceRoundingAdjustment(modifiedTotal, options?.isFirstInsurance);
137	}
138	
139	export function createQuote(items: unknown[], options?: QuoteOptions): number {
140	  const quoteItems = items as QuoteItem[];
141	  if (quoteItems.length === 0) {
142	    return PROCESSING_FEE;
143	  }
144	
145	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
146	  const fee = calculateProcessingFee(quoteItems);
147	  const baseTotal = totalPremium + fee;
148	
149	  return applyQuoteModifiers(baseTotal, options);
150	}
151	
152	interface ClaimPolicy {
153	  items: QuoteItem[];
154	  coverage: number;
155	}
156	
157	interface Damage {
158	  type: string;
159	  amount: number;
160	}
161	
162	const DEDUCTIBLE = 100;
163	
164	function findDamageItem(policy: ClaimPolicy, damageType: string): QuoteItem | undefined {
165	  return policy.items.find(item => item.type === damageType);
166	}
167	
168	function calculatePayoutForHighEnchantment(basePayout: number, coverage: number): number {
169	  return Math.min(basePayout * 2, coverage * 4);
170	}
171	
172	function calculateStandardPayout(basePayout: number, coverage: number): number {
173	  return Math.min(basePayout, coverage * 2);
174	}
175	
176	export function processClaim(policy: ClaimPolicy, damage: Damage): number {
177	  const damageItem = findDamageItem(policy, damage.type);
178	
179	  if (damageItem?.dragonMaterial) {
180	    return damage.amount;
181	  }
182	
183	  if (damage.amount <= DEDUCTIBLE) {
184	    return 0;
185	  }
186	
187	  const basePayout = damage.amount - DEDUCTIBLE;
188	  const itemHasHighEnchantment = damageItem && isHighEnchantment(damageItem);
189	
190	  if (itemHasHighEnchantment) {
191	    return calculatePayoutForHighEnchantment(basePayout, policy.coverage);
192	  }
193	
194	  return calculateStandardPayout(basePayout, policy.coverage);
195	}
196	
197	export function processMultipleDamages(policy: ClaimPolicy, damages: Damage[]): number {
198	  return damages.reduce((total, damage) => total + processClaim(policy, damage), 0);
199	}
